+export class RuleUtils {
+  /**
+   * Safely parses an expression string like ">=58" or ">58" into operator and threshold.
+   * This avoids using eval or new Function() which can lead to code injection.
+   *
+   * @param expression - The expression string to parse (e.g., ">=58", "<60")
+   * @returns Object with operator and threshold, or null if invalid
+   */
+  static parseExpression(expression: string): {operator: string; threshold: number} | null {
+    if (!expression || typeof expression !== 'string') {
+      return null;
+    }
+
+    // Match valid operators followed by digits
+    const match = expression.match(/^(>=|<=|>|<|==|=)?\s*(\d+)$/);
+    if (!match) {
+      return null;
+    }
+
+    const operator = (match[1] || '>=').trim();
+    const threshold = parseInt(match[2], 10);
+
+    if (isNaN(threshold)) {
+      return null;
+    }
+
+    return {operator, threshold};
+  }
+}

